## Book.java

```java
package com.haddley.Books;

public class Book {

	public Book(long id, String title) {
		_id = id;
		_title = title;
	}

	private long _id;

	public long getId() {
		return _id;
	}

	public void setId(long id) {
		this._id = id;
	}

	public String getTitle() {
		return _title;
	}

	public void setTitle(String title) {
		this._title = title;
	}

	private String _title;

}
```

## BooksRestController.java

```java
package com.haddley.Books;

import java.util.ArrayList;

import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.server.ResponseStatusException;


@RestController
public class BooksRestController {

	private static ArrayList<Book> books = new ArrayList<Book>();

	static {
		books.add(new Book(1788395549, "Learning Node.js Development"));
		books.add(new Book(1788620216, "Hands-On Microservices with Node.js"));
	}

	@GetMapping("/books/{id}")
	public Book book(@PathVariable Long id) {
		@SuppressWarnings("unchecked")
		ArrayList<Book> result = (ArrayList<Book>) BooksRestController.books.clone();
		result.removeIf(n -> (n.getId() != id));
		if (result.isEmpty()){
			throw new ResponseStatusException(HttpStatus.NOT_FOUND, "Book Not Found");
		}
		return result.get(0);
	}

	@GetMapping("/books")
	public ArrayList<Book> books() {
		return BooksRestController.books;
	}

}
```

## App.js

```javascript
import React, { useEffect, useState } from 'react';

function App() {

  const [books, setBooks] = useState([]);

  useEffect(() => {

    console.log("use effect");
    fetch('/books')
      .then(
        (d) => {
          d.json().then((b) => {
            setBooks(() => b)
          });
        }
      )

  }
    , [])

  return (

    <>
        {books.map(book =>
            <h4>{book.title}</h4>)}
    </>

  );
}

export default App;
```

